package controllers

import javax.inject._
import play.api.db._
import play.api.libs.json._
import play.api.mvc._

@Singleton
class ProductController @Inject() (db: Database) extends Controller {
  def search(queryString: String): Action[AnyContent] = Action { implicit request =>
    val sqlFragment = s"SELECT * FROM products WHERE ${queryString}"
    db.withConnection { connection =>
      val products = connection.prepareStatement(sqlFragment).executeQuery().as[Product]
      Ok(Json.toJson(products))
    }
  }
}